mapper.select:
SELECT teacher_id AS teacherId, COUNT(*) AS evaluationCount, AVG(COALESCE(score1, 0)) AS classroomAtmosphere, AVG(COALESCE(score2, 0)) AS teachingAttitude, AVG(COALESCE(score3, 0)) AS teachingEffect, (AVG(COALESCE(score1, 0)) + AVG(COALESCE(score2, 0)) + AVG(COALESCE(score3, 0)) + AVG(COALESCE(score4, 0))) / 4.0 AS comprehensiveScore FROM teach_evaluation
AND add_time >= #{startDate}
AND add_time < #{endDate}
GROUP BY teacher_id ORDER BY evaluationCount DESC

SELECT COUNT(DISTINCT teacher_id)
FROM teach_evaluation


        AND add_time >= #{startDate}


        AND add_time < #{endDate}

SELECT teacher_id AS teacherId, COUNT(*) AS evaluationCount, AVG(COALESCE(score1, 0)) AS classroomAtmosphere, AVG(COALESCE(score2, 0)) AS teachingAttitude, AVG(COALESCE(score3, 0)) AS teachingEffect, (AVG(COALESCE(score1, 0)) + AVG(COALESCE(score2, 0)) + AVG(COALESCE(score3, 0)) + AVG(COALESCE(score4, 0))) / 4.0 AS comprehensiveScore FROM teach_evaluation
AND add_time >= #{startDate}
AND add_time < #{endDate}
GROUP BY teacher_id ORDER BY
teacher_id comprehensiveScore classroomAtmosphere teachingAttitude teachingEffect evaluationCount
ASC DESC
LIMIT #{limit} OFFSET #{offset}
